using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;/// <summary>/// Good case: Retrieve EHR document with valid requester ID/// Expected: 200 OK with document content/// </summary>public class EhrServiceTests_GetEhrDocument_WithValidRequesterId_ShouldReturnDocument : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService",        "ConsentService"    };    [SkippableFact]    public async Task GetEhrDocument_WithValidRequesterId_ShouldReturnDocument()    {        await AuthenticateAsDoctorAsync(EhrClient);        // Step 1: Create an EHR record        var createRequest = new         {             patientId = TestSeedData.PatientUserId,             orgId = TestSeedData.HospitalAOrgId,             encounterId = Guid.NewGuid(),             data = new             {                 doctorId = TestSeedData.DoctorUserId,                 diagnosis = "Document test",                 treatment = "Test treatment",                 notes = "Test notes"             }         };        var createResponse = await PostAsJsonWithRetryAsync(EhrClient, ApiEndpoints.Ehr.CreateRecord, createRequest);        var createJson = await ReadJsonResponseAsync(createResponse);                if (!createJson.TryGetProperty("ehrId", out var ehrIdElement))            return; // Skip if creation fails        var ehrId = Guid.Parse(ehrIdElement.GetString()!);        // Step 2: Get document with valid requester ID (doctor can access their own records)        var getRequest = EhrClient.CreateRequest(HttpMethod.Get, ApiEndpoints.Ehr.GetDocument(ehrId));        getRequest.Headers.Add("X-Requester-Id", TestSeedData.DoctorUserId.ToString());        var response = await EhrClient.SendAsync(getRequest);        // Document retrieval may return 200 OK or 403 Forbidden depending on consent        Assert.True(            response.StatusCode == HttpStatusCode.OK ||             response.StatusCode == HttpStatusCode.Forbidden ||            response.StatusCode == HttpStatusCode.NotFound,            $"Expected 200, 403, or 404, got {response.StatusCode}");    }}